```python
#!/usr/bin/env python
# -*- coding: utf-8 -*-

"""
高级会话分析页面 - 提供可视化、JSON编辑和深度分析功能
"""

import json
import gradio as gr
from session_logger import get_logger

def create_session_analyzer():
    """
    创建高级会话分析界面

    优化改进：
    1. 移除手动刷新按钮 - 会话总览页面自动加载
    2. 移除会话详情下拉菜单 - 直接显示最新会话，每5秒自动刷新
    3. 会话列表项可点击 - 点击任意会话可查看详情
    4. 移除数据导出tab - 简化界面
    5. 自动显示最新会话 - 无需手动选择

    Returns:
        demo: Gradio Blocks 应用
    """

    logger = get_logger()

    # 自定义CSS - 增强可视化
    custom_css = """
    <script>
    // 全局函数用于选择会话并切换到详情Tab
    window.selectSession = function(sessionId) {
        try {
            console.log('Selecting session:', sessionId);

            // 1. 找到隐藏的textbox元素并设置值
            const selector = document.getElementById('session_id_selector');
            if (selector) {
                console.log('Found selector element');

                // 查找textarea或input元素
                const input = selector.querySelector('textarea') || selector.querySelector('input');
                if (input) {
                    console.log('Found input element, setting value:', sessionId);
                    input.value = sessionId;

                    // 触发input事件让Gradio检测到值的变化
                    const inputEvent = new Event('input', { bubbles: true });
                    input.dispatchEvent(inputEvent);

                    // 延迟后触发change事件
                    setTimeout(() => {
                        const changeEvent = new Event('change', { bubbles: true });
                        input.dispatchEvent(changeEvent);
                        console.log('Dispatched change event');
                    }, 100);
                } else {
                    console.log('No input element found');
                }
            } else {
                console.log('No selector element found');
            }

            // 2. 点击刷新按钮以加载会话详情
            setTimeout(() => {
                const refreshBtn = document.getElementById('refresh_session_btn');
                if (refreshBtn) {
                    console.log('Found refresh button, clicking it');
                    const btn = refreshBtn.querySelector('button');
                    if (btn) {
                        btn.click();
                        console.log('Clicked refresh button');
                    }
                } else {
                    console.log('No refresh button found');
                }
            }, 150);

            // 3. 切换到"会话详情"Tab
            setTimeout(() => {
                // 查找所有的tab按钮
                const tabButtons = document.querySelectorAll('[role="tab"]');
                if (tabButtons.length > 0) {
                    const detailsTab = tabButtons.find(tab => tab.textContent.includes('Details'));
                    if (detailsTab) {
                        detailsTab.click();
                        console.log('Clicked Details tab');
                    }
                }
            }, 200);
        } catch (e) {
            console.error('Error selecting session:', e);
        }
    };
    </script>
    """

    demo = gr.Blocks(css=custom_css)

    # 添加组件到界面
    with demo:
        # ... (代码中省略了具体的组件和逻辑)

    return demo

if __name__ == "__main__":
    import socket

    def find_free_port(start=7862, attempts=10):
        for port in range(start, start + attempts):
            try:
                sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                result = sock.connect_ex(('127.0.0.1', port))
                sock.close()
                if result != 0:
                    return port
            except:
                pass
        return 7862

    port = find_free_port()
    print(f"✅ 高级分析页面运行在端口 {port}")

    demo = create_session_analyzer()
    demo.launch(
        server_name="0.0.0.0",
        server_port=port,
        inbrowser=True,
        share=False,
        show_error=True,
    )
```

这段代码定义了一个 `create_session_analyzer` 函数，该函数创建了一个使用 Gradio 库的界面，用于会话分析。代码中还包含了一些优化改进的说明，以及一个用于查找空闲端口的函数。最后，代码启动了一个服务器，并在指定的端口上运行界面。

